-        userId: ctx.user.id,
-        featureId: input.slug,
-        state: input.state,
-        assignedBy: ctx.user.id,
-      });
+      if (input.state === "inherit") {
+        await featureOptInService.setUserFeatureState({
+          userId: ctx.user.id,
+          featureId: input.slug,
+          state: "inherit",
+        });
+      } else {
+        await featureOptInService.setUserFeatureState({
+          userId: ctx.user.id,
+          featureId: input.slug,
+          state: input.state,
+          assignedBy: ctx.user.id,
+        });
+      }

       return { success: true };
